Nivel 1 — Ejemplo Mínimo: Simulación de rectificación de media onda en C/C++
En sistemas embebidos, se modela numéricamente la salida de un diodo no ideal de sili-
cio aplicando un voltaje de corriente alterna sinusoidal de entrada, restando la caída de
barrera directa del material semiconductor (Vdrop ≈0.7 V):

1
#include <iostream >

2
#include <cmath>

3
#include <iomanip >

4
#include <string >

5

6
// Simulacion numerica de rectificacion de media onda usando un diodo de

silicio real

7
// V_in(t) = V_peak * sin(w * t)

8
// V_out(t) = max(0, V_in(t) - V_drop) donde V_drop = 0.7V para Silicio

comercial

9

10
int main() {

11
const double V_peak = 5.0;
// Tension de pico de CA de entrada (5.0

V)

12
const double V_drop = 0.7;
// Caida de tension directa de barrera

PN de Silicio

13
const double pi = 3.141592653589793;

14

15
std::cout << std::fixed << std::setprecision(2);

16
std::cout << "Angulo␣(grados)\tVoltaje␣In␣(V)\tVoltaje␣Out␣(V)\

tEstado␣del␣Diodo\n";

17
std::cout << "

-----------------------------------------------------------------\
n";

18

19
// Muestreo del ciclo completo de CA de 0 a 360 grados en pasos de 30

grados

20
for (int deg = 0; deg <= 360; deg += 30) {

21
double rad = deg * (pi / 180.0);

22
double V_in = V_peak * std::sin(rad);

23
double V_out = 0.0;

24
std::string state;

25

26
// Comportamiento no ideal: el diodo conduce si la tension supera

los 0.7V

27
if (V_in > V_drop) {

28
V_out = V_in - V_drop;

29
state = "ON␣(Conduccion)";

30
} else {

31
V_out = 0.0;

32
state = "OFF␣(Bloqueo)";

33
}

34

35
std::cout << deg << "␣deg\t\t" << V_in << "␣V\t\t" << V_out << "␣

V\t\t" << state << "\n";

36
}

37
return 0;

38
}

