Nivel 1 — Ejemplo Mínimo: Conmutación de carga inductiva con MOSFET en C/C++
En sistemas digitales embebidos de hardware, un puerto lógico GPIO de baja corriente
no puede manejar directamente cargas pesadas (como un motor de CC o solenoide). Se
utiliza un MOSFET canal N como interruptor electrónico de baja impedancia controlado
por el pin del microcontrolador:

1
// Control de compuerta de un MOSFET canal N para activar un motor de CC.

2
// V_GPIO: Salida de compuerta (0.0V para LOW, 3.3V para HIGH).

3
// V_th (Voltaje de umbral del MOSFET) = 1.8V para activacion a nivel

logico.

4

5
const int gatePin = 5; // Pin GPIO5 conectado a la compuerta del MOSFET

6

7
void setup() {

8
// Configura el GPIO como salida digital de baja resistencia de

salida

9
pinMode(gatePin , OUTPUT);

10
}

11

12
void loop() {

13
// Aplica 3.3V en compuerta (V_GS > V_th). El canal se induce.

14
// El MOSFET entra en zona de saturacion activa y conduce corriente.

15
digitalWrite(gatePin , HIGH);

16
delay(5000); // Mantiene el motor encendido por 5 segundos

17

18
// Aplica 0.0V en compuerta (V_GS < V_th). El canal de conduccion se

extingue.

19
// El MOSFET entra en corte, abriendo el circuito.

20
digitalWrite(gatePin , LOW);

21
delay(5000); // Mantiene el motor apagado por 5 segundos

22
}

Nivel 1 — Ejemplo Mínimo: Evaluación y enmascaramiento lógico a nivel de bits en
C/C++
En sistemas embebidos e informática de bajo nivel, se utilizan los operadores lógicos bit-
wise para evaluar y filtrar estados del puerto físico a nivel de hardware, aplicando opera-
ciones booleanas de máscara lógica directa:

1
#include <iostream >

2
#include <iomanip >

3

4
// Demostracion de operaciones booleanas bitwise a nivel de bits

5
// AND bitwise (&): Utilizado para filtrar o enmascarar pines especificos

.

6
// OR bitwise (|): Utilizado para forzar pines a estado activo.

7
// NOT bitwise (~): Inversion total de los registros.

8

9
int main() {

10
// Registro representativo del puerto de Entrada/Salida de 8 bits

11
unsigned char port_state = 0b10101100; // Estado real actual del

puerto

12
unsigned char pin_mask
= 0b00001100; // Mascara para filtrar pines

2 y 3

13

14
// Operacion AND logica Booleana bitwise

15
unsigned char status = port_state & pin_mask;

16

17
std::cout << std::hex << std::showbase;

18
std::cout << "Estado␣Original:␣␣" << (int)port_state << "␣(Binario:␣

10101100)\n";

19
std::cout << "Mascara␣de␣Pines:␣" << (int)pin_mask
<< "␣(Binario:␣

00001100)\n";

20
std::cout << "Resultado␣Filtro:␣" << (int)status
<< "␣(Binario:␣

00001100)\n";

21

22
if (status == pin_mask) {

23
std::cout << "Resultado:␣Pines␣de␣control␣2␣y␣3␣activos␣

simultaneamente.\n";

24
} else {

25
std::cout << "Resultado:␣Pines␣inactivos␣o␣faltantes.\n";

26
}

27
return 0;

28
}

Nivel 1 — Ejemplo Mínimo: Modelado síncrono de un registro PIPO de 4 bits en C/C++
El siguiente programa en C++ simula el comportamiento físico de un registro PIPO de 4 bits
controlado por flanco ascendente de reloj e incorpora un pin de habilitación de escritura
(Write Enable), modelando la recirculación de estados del hardware:

1
#include <iostream >

2
#include <vector >

3

4
// Clase que modela el comportamiento de un registro paralelo síncrono

5
class RegisterPIPO4 {

6
private:

7
std::vector <bool> Q; // Salidas del registro (Estado actual)

8

9
public:

10
RegisterPIPO4() : Q(4, false) {} // Inicialización en 0000

11

12
// Función que modela la transición síncrona ante un flanco de reloj

13
void clock_edge(const std::vector<bool >& D, bool WE, bool CLK) {

14
// Solo ocurre transición si hay flanco ascendente de reloj (CLK

= true)

15
if (CLK) {

16
if (WE) {

17
// Si la habilitación de escritura está activa , carga

nuevos datos

18
Q = D;

19
}

20
// Si WE es falso, el estado Q se recircula y permanece

inalterado

21
}

22
}

23

24
void display() const {

25
std::cout << "[␣";

26
for (int i = 3; i >= 0; --i) {

27
std::cout << Q[i] << "␣";

28
}

29
std::cout << "]\n";

30
}

31
};

32

33
int main() {

34
RegisterPIPO4 reg;

35
std::vector <bool> data_bus = {true, false, true, true}; // Dato: 1011

36

37
std::cout << "Estado␣Inicial:␣"; reg.display();

38

39
// Intento de carga sin habilitación (WE = false) ante flanco de

reloj

40
reg.clock_edge(data_bus , false, true);

41
std::cout << "Luego␣de␣CLK␣con␣WE=0:␣"; reg.display();

42

43
// Carga de datos activa (WE = true) ante flanco de reloj

44
reg.clock_edge(data_bus , true, true);

45
std::cout << "Luego␣de␣CLK␣con␣WE=1␣(Carga):␣"; reg.display();

46

47
return 0;

48
}

