Nivel 1 — Ejemplo Mínimo: Modelado de un contador binario síncrono de 3 bits en
C/C++
El siguiente programa en C++ simula el comportamiento físico de un registro contador
binario síncrono de 3 bits (Mod-8) controlado por el flanco ascendente de reloj, ilustrando
la evolución de las variables físicas lógicas:

1
#include <iostream >

2
#include <iomanip >

3

4
// Clase que modela un contador síncrono de 3 bits (Secuencia: 0 a 7)

5
class BinaryCounter3 {

6
private:

7
unsigned char count; // Estado de almacenamiento interno (3 bits

útiles)

8

9
public:

10
BinaryCounter3() : count(0) {}

11

12
// Transición de estado síncrona ante la señal de reloj activa (CLK =

true)

13
void clock_edge(bool CLK) {

14
if (CLK) {

15
// Evolución de la cuenta síncrona modulo 8 (3 bits: 000 a

111)

16
count = (count + 1) & 0x07;

17
}

18
}

19

20
void display() const {

21
std::cout << "Binario:␣";

22
for (int i = 2; i >= 0; --i) {

23
std::cout << ((count >> i) & 1) << "␣";

24
}

25
std::cout << "\t(Decimal:␣" << (int)count << ")\n";

26
}

27
};

28

29
int main() {

30
BinaryCounter3 my_counter;

31

32
std::cout << "Inicialización␣del␣contador:\n";

33
my_counter.display();

34
std::cout << "-------------------------------------------\n";

35

36
// Simulación de 10 ciclos de reloj consecutivos

37
for (int cycle = 1; cycle <= 10; ++cycle) {

38
my_counter.clock_edge(true); // Flanco de reloj ascendente activo

39
std::cout << "Ciclo␣de␣Reloj␣" << std::setw(2) << cycle << "␣->␣"

;

40
my_counter.display();

41
}

42
return 0;

43
}
